const result = [];

for (const item of $input.all()) {
  const change = item.json;

  const rawOutput = change.content?.parts?.[0]?.text || "";

  let summary = "No summary generated";
  if (rawOutput.includes("Summary:") && rawOutput.includes("Key Changes:")) {
    summary = rawOutput.split("Summary:")[1].split("Key Changes:")[0].trim();
  } else if (rawOutput) {
    summary = rawOutput.trim();
  }

  let keyChanges = "None";
  if (rawOutput.includes("Key Changes:")) {
    const keyPart = rawOutput.split("Key Changes:")[1].trim();
    const lines = keyPart.split("\n");
    const extractedKeyChanges = [];
    for (let line of lines) {
      line = line.trim().replace(/^[-*•]\s*/, "");
      if (line && line.toLowerCase() !== "none") {
        extractedKeyChanges.push(line);
      }
    }
    keyChanges = extractedKeyChanges.length > 0 ? extractedKeyChanges.join(" | ") : "None";
  }

  result.push({
    json: {
      Title: change.title,
      Source: typeof change.source === "object" ? change.source.name : (change.source || "Unknown"),
      Published_At: change.publishedAt,
      URL: change.url,
      Content: change.content || change.description || "",
      Summary: summary,
      "Key Changes": keyChanges
    }
  });
}

return result;

